     1→/**
     2→ * ConvergioEdu Conversation Flow Store
     3→ *
     4→ * Manages the state of the conversation-first interface:
     5→ * - Current active character (Coach, Maestro, Buddy)
     6→ * - SEPARATE conversations per character (#33)
     7→ * - Character routing and handoffs
     8→ *
     9→ * Part of I-01: Conversation-First Main Flow
    10→ * Related: #24 MirrorBuddy Issue, #33 Separate Conversations, ManifestoEdu.md
    11→ */
    12→
    13→import { create } from 'zustand';
    14→import type { CharacterType, ExtendedStudentProfile } from '@/types';
    15→import type { MaestroFull } from '@/data/maestri';
    16→import type { SupportTeacher } from '@/types';
    17→import type { BuddyProfile } from '@/types';
    18→import {
    19→  routeToCharacter,
    20→  getCharacterGreeting as _getCharacterGreeting,
    21→  getCharacterSystemPrompt as _getCharacterSystemPrompt,
    22→  type RoutingResult,
    23→} from '@/lib/ai/character-router';
    24→import { getDefaultSupportTeacher, getSupportTeacherById, type CoachId } from '@/data/support-teachers';
    25→import { getBuddyForStudent } from '@/lib/ai/character-router';
    26→import { getBuddyById, type BuddyId } from '@/data/buddy-profiles';
    27→import { getMaestroById } from '@/data/maestri';
    28→import { logger } from '@/lib/logger';
    29→
    30→// ============================================================================
    31→// PERSISTENCE HELPERS
    32→// ============================================================================
    33→
    34→/**
    35→ * Create a new conversation in the database.
    36→ */
    37→async function createConversationInDB(
    38→  characterId: string,
    39→  characterType: CharacterType,
    40→  characterName: string
    41→): Promise<string | null> {
    42→  try {
    43→    const response = await fetch('/api/conversations', {
    44→      method: 'POST',
    45→      headers: { 'Content-Type': 'application/json' },
    46→      body: JSON.stringify({
    47→        maestroId: characterId,
    48→        title: `Conversazione con ${characterName}`,
    49→      }),
    50→    });
    51→    if (!response.ok) {
    52→      logger.error('Failed to create conversation', { status: response.status });
    53→      return null;
    54→    }
    55→    const data = await response.json();
    56→    logger.debug('Created conversation', { id: data.id, characterId });
    57→    return data.id;
    58→  } catch (error) {
    59→    logger.error('Error creating conversation', { error: String(error) });
    60→    return null;
    61→  }
    62→}
    63→
    64→/**
    65→ * Save a message to the database.
    66→ */
    67→async function saveMessageToDB(
    68→  conversationId: string,
    69→  role: string,
    70→  content: string
    71→): Promise<void> {
    72→  try {
    73→    const response = await fetch(`/api/conversations/${conversationId}/messages`, {
    74→      method: 'POST',
    75→      headers: { 'Content-Type': 'application/json' },
    76→      body: JSON.stringify({ role, content }),
    77→    });
    78→    if (!response.ok) {
    79→      logger.error('Failed to save message', { status: response.status });
    80→    }
    81→  } catch (error) {
    82→    logger.error('Error saving message', { error: String(error) });
    83→  }
    84→}
    85→
    86→/**
    87→ * Conversation summary from DB (used for context, not full message restoration).
    88→ */
    89→interface ConversationSummary {
    90→  id: string;
    91→  maestroId: string;
    92→  title: string;
    93→  summary: string | null;
    94→  keyFacts: string[] | null;
    95→  topics: string[];
    96→  messageCount: number;
    97→  lastMessageAt: string | null;
    98→}
    99→
   100→/**
   101→ * Load conversation summaries from the database (not full messages).
   102→ * We use summaries for context instead of restoring entire conversations.
   103→ */
   104→async function loadConversationSummariesFromDB(): Promise<ConversationSummary[]> {
   105→  try {
   106→    const response = await fetch('/api/conversations?limit=20&active=true');
   107→
   108→    // 401 = no user cookie yet (first visit), not an error
   109→    if (response.status === 401) {
   110→      return [];
   111→    }
   112→
   113→    if (!response.ok) {
   114→      logger.warn('Conversations API returned error', { status: response.status });
   115→      return [];
   116→    }
   117→
   118→    const data = await response.json();
   119→
   120→    // API might return error object instead of array
   121→    if (!Array.isArray(data)) {
   122→      if (data.error) {
   123→        logger.warn('Conversations API error', { error: data.error });
   124→      }
   125→      return [];
   126→    }
   127→
   128→    return data;
   129→  } catch (error) {
   130→    // Network error or JSON parse error
   131→    logger.warn('Error loading conversation summaries', { error: String(error) });
   132→    return [];
   133→  }
   134→}
   135→
   136→/**
   137→ * Update conversation summary in DB.
   138→ * TODO: Call this when ending a conversation to save summary for future context.
   139→ */
   140→async function _updateConversationSummary(
   141→  conversationId: string,
   142→  summary: string,
   143→  keyFacts: string[],
   144→  topics: string[]
   145→): Promise<void> {
   146→  try {
   147→    await fetch(`/api/conversations/${conversationId}`, {
   148→      method: 'PUT',
   149→      headers: { 'Content-Type': 'application/json' },
   150→      body: JSON.stringify({ summary, keyFacts: JSON.stringify(keyFacts), topics }),
   151→    });
   152→  } catch (error) {
   153→    logger.error('Error updating conversation summary', { error: String(error) });
   154→  }
   155→}
   156→
   157→// ============================================================================
   158→// TYPES
   159→// ============================================================================
   160→
   161→/**
   162→ * Active character in the conversation.
   163→ */
   164→export interface ActiveCharacter {
   165→  type: CharacterType;
   166→  id: string;
   167→  name: string;
   168→  character: MaestroFull | SupportTeacher | BuddyProfile;
   169→  greeting: string;
   170→  systemPrompt: string;
   171→  color: string;
   172→  voice: string;
   173→  voiceInstructions: string;
   174→  subtitle?: string;
   175→}
   176→
   177→/**
   178→ * A message in the conversation flow.
   179→ */
   180→export interface FlowMessage {
   181→  id: string;
   182→  role: 'user' | 'assistant' | 'system';
   183→  content: string;
   184→  timestamp: Date;
   185→  characterId?: string;
   186→  characterType?: CharacterType;
   187→  /** If this message triggered a character switch */
   188→  switchedTo?: {
   189→    type: CharacterType;
   190→    id: string;
   191→    reason: string;
   192→  };
   193→}
   194→
   195→/**
   196→ * Stored conversation for a character.
   197→ */
   198→export interface CharacterConversation {
   199→  characterId: string;
   200→  characterType: CharacterType;
   201→  characterName: string;
   202→  messages: FlowMessage[];
   203→  lastMessageAt: Date | null;
   204→  conversationId?: string; // DB conversation ID if synced
   205→  // Summary for context (loaded from DB, not full messages)
   206→  previousSummary?: string;
   207→  previousKeyFacts?: string[];
   208→  previousTopics?: string[];
   209→}
   210→
   211→/**
   212→ * Handoff suggestion from character routing.
   213→ */
   214→export interface HandoffSuggestion {
   215→  toCharacter: ActiveCharacter;
   216→  reason: string;
   217→  confidence: number;
   218→}
   219→
   220→/**
   221→ * Conversation flow mode.
   222→ */
   223→export type FlowMode = 'text' | 'voice' | 'idle';
   224→
   225→// ============================================================================
   226→// STORE
   227→// ============================================================================
   228→
   229→interface ConversationFlowState {
   230→  // Current state
   231→  mode: FlowMode;
   232→  isActive: boolean;
   233→  activeCharacter: ActiveCharacter | null;
   234→  messages: FlowMessage[]; // Current character's messages (displayed)
   235→  pendingHandoff: HandoffSuggestion | null;
   236→
   237→  // SEPARATE CONVERSATIONS PER CHARACTER (#33)
   238→  conversationsByCharacter: Record<string, CharacterConversation>;
   239→
   240→  // Session tracking
   241→  sessionId: string | null;
   242→  sessionStartedAt: Date | null;
   243→
   244→  // Character history (for back navigation)
   245→  characterHistory: Array<{ type: CharacterType; id: string; timestamp: Date }>;
   246→
   247→  // Actions
   248→  startConversation: (profile: ExtendedStudentProfile) => void;
   249→  endConversation: () => void;
   250→  setMode: (mode: FlowMode) => void;
   251→
   252→  // Message actions
   253→  addMessage: (message: Omit<FlowMessage, 'id' | 'timestamp'>) => Promise<void>;
   254→  clearMessages: () => void;
   255→
   256→  // Character routing
   257→  routeMessage: (message: string, profile: ExtendedStudentProfile) => RoutingResult;
   258→  switchToCharacter: (
   259→    character: MaestroFull | SupportTeacher | BuddyProfile,
   260→    type: CharacterType,
   261→    profile: ExtendedStudentProfile,
   262→    reason?: string
   263→  ) => void;
   264→  switchToCoach: (profile: ExtendedStudentProfile) => void;
   265→  switchToMaestro: (maestro: MaestroFull, profile: ExtendedStudentProfile) => void;
   266→  switchToBuddy: (profile: ExtendedStudentProfile) => void;
   267→  goBack: (profile: ExtendedStudentProfile) => boolean;
   268→
   269→  // Handoff management
   270→  suggestHandoff: (suggestion: HandoffSuggestion) => void;
   271→  acceptHandoff: (profile: ExtendedStudentProfile) => void;
   272→  dismissHandoff: () => void;
   273→
   274→  // Conversation history
   275→  getConversationForCharacter: (characterId: string) => CharacterConversation | null;
   276→  getAllConversations: () => CharacterConversation[];
   277→
   278→  // Reset
   279→  reset: () => void;
   280→
   281→  // Persistence
   282→  loadFromServer: () => Promise<void>;
   283→}
   284→
   285→/**
   286→ * Creates an ActiveCharacter from character data.
   287→ */
   288→function createActiveCharacter(
   289→  character: MaestroFull | SupportTeacher | BuddyProfile,
   290→  type: CharacterType,
   291→  profile: ExtendedStudentProfile
   292→): ActiveCharacter {
   293→  let greeting: string;
   294→  let systemPrompt: string;
   295→  let voiceInstructions: string;
   296→
   297→  if (type === 'buddy') {
   298→    const buddy = character as BuddyProfile;
   299→    greeting = buddy.getGreeting(profile);
   300→    systemPrompt = buddy.getSystemPrompt(profile);
   301→    voiceInstructions = buddy.voiceInstructions;
   302→  } else if (type === 'coach') {
   303→    const coach = character as SupportTeacher;
   304→    greeting = coach.greeting;
   305→    systemPrompt = coach.systemPrompt;
   306→    voiceInstructions = coach.voiceInstructions;
   307→  } else {
   308→    const maestro = character as MaestroFull;
   309→    greeting = maestro.greeting;
   310→    systemPrompt = maestro.systemPrompt;
   311→    voiceInstructions = '';
   312→  }
   313→
   314→  return {
   315→    type,
   316→    id: character.id,
   317→    name: character.name,
   318→    character,
   319→    greeting,
   320→    systemPrompt,
   321→    color: character.color,
   322→    voice: 'voice' in character ? character.voice : 'alloy',
   323→    voiceInstructions,
   324→  };
   325→}
   326→
   327→/**
   328→ * Save current messages to character's conversation bucket.
   329→ */
   330→function saveCurrentConversation(
   331→  state: ConversationFlowState
   332→): Record<string, CharacterConversation> {
   333→  if (!state.activeCharacter || state.messages.length === 0) {
   334→    return state.conversationsByCharacter;
   335→  }
   336→
   337→  const characterId = state.activeCharacter.id;
   338→  const existingConvo = state.conversationsByCharacter[characterId];
   339→
   340→  return {
   341→    ...state.conversationsByCharacter,
   342→    [characterId]: {
   343→      characterId,
   344→      characterType: state.activeCharacter.type,
   345→      characterName: state.activeCharacter.name,
   346→      messages: state.messages,
   347→      lastMessageAt: new Date(),
   348→      conversationId: existingConvo?.conversationId,
   349→    },
   350→  };
   351→}
   352→
   353→/**
   354→ * Load messages for a character from their conversation bucket.
   355→ */
   356→function loadConversationMessages(
   357→  conversationsByCharacter: Record<string, CharacterConversation>,
   358→  characterId: string
   359→): FlowMessage[] {
   360→  const convo = conversationsByCharacter[characterId];
   361→  return convo?.messages || [];
   362→}
   363→
   364→export const useConversationFlowStore = create<ConversationFlowState>()(
   365→  (set, get) => ({
   366→      mode: 'idle',
   367→      isActive: false,
   368→      activeCharacter: null,
   369→      messages: [],
   370→      pendingHandoff: null,
   371→      conversationsByCharacter: {},
   372→      sessionId: null,
   373→      sessionStartedAt: null,
   374→      characterHistory: [],
   375→
   376→      startConversation: (profile) => {
   377→        const coach = getDefaultSupportTeacher();
   378→        const activeCharacter = createActiveCharacter(coach, 'coach', profile);
   379→
   380→        // Check if we have existing conversation with this coach
   381→        const state = get();
   382→        const existingMessages = loadConversationMessages(
   383→          state.conversationsByCharacter,
   384→          coach.id
   385→        );
   386→
   387→        // If no existing messages, start with greeting
   388→        const messages: FlowMessage[] =
   389→          existingMessages.length > 0
   390→            ? existingMessages
   391→            : [
   392→                {
   393→                  id: crypto.randomUUID(),
   394→                  role: 'assistant',
   395→                  content: activeCharacter.greeting,
   396→                  timestamp: new Date(),
   397→                  characterId: activeCharacter.id,
   398→                  characterType: 'coach',
   399→                },
   400→              ];
   401→
   402→        set({
   403→          isActive: true,
   404→          mode: 'text',
   405→          activeCharacter,
   406→          messages,
   407→          sessionId: crypto.randomUUID(),
   408→          sessionStartedAt: new Date(),
   409→          characterHistory: [{ type: 'coach', id: coach.id, timestamp: new Date() }],
   410→          pendingHandoff: null,
   411→        });
   412→      },
   413→
   414→      endConversation: () => {
   415→        // Save current conversation before ending
   416→        const state = get();
   417→        const updatedConversations = saveCurrentConversation(state);
   418→
   419→        set({
   420→          isActive: false,
   421→          mode: 'idle',
   422→          activeCharacter: null,
   423→          messages: [],
   424→          pendingHandoff: null,
   425→          sessionId: null,
   426→          sessionStartedAt: null,
   427→          characterHistory: [],
   428→          conversationsByCharacter: updatedConversations,
   429→        });
   430→      },
   431→
   432→      setMode: (mode) => set({ mode }),
   433→
   434→      addMessage: async (message) => {
   435→        const state = get();
   436→        const newMessage: FlowMessage = {
   437→          ...message,
   438→          id: crypto.randomUUID(),
   439→          timestamp: new Date(),
   440→          characterId: message.role === 'assistant' ? state.activeCharacter?.id : undefined,
   441→          characterType: message.role === 'assistant' ? state.activeCharacter?.type : undefined,
   442→        };
   443→
   444→        const newMessages = [...state.messages, newMessage];
   445→
   446→        // Also update the conversation bucket
   447→        const characterId = state.activeCharacter?.id;
   448→        let updatedConversations = state.conversationsByCharacter;
   449→        let conversationId = state.conversationsByCharacter[characterId || '']?.conversationId;
   450→
   451→        if (characterId && state.activeCharacter) {
   452→          // Create conversation in DB if not exists
   453→          if (!conversationId) {
   454→            conversationId = await createConversationInDB(
   455→              characterId,
   456→              state.activeCharacter.type,
   457→              state.activeCharacter.name
   458→            ) || undefined;
   459→          }
   460→
   461→          updatedConversations = {
   462→            ...state.conversationsByCharacter,
   463→            [characterId]: {
   464→              characterId,
   465→              characterType: state.activeCharacter.type,
   466→              characterName: state.activeCharacter.name,
   467→              messages: newMessages,
   468→              lastMessageAt: new Date(),
   469→              conversationId,
   470→            },
   471→          };
   472→
   473→          // Persist message to DB (fire and forget)
   474→          if (conversationId) {
   475→            saveMessageToDB(conversationId, newMessage.role, newMessage.content);
   476→          }
   477→        }
   478→
   479→        set({
   480→          messages: newMessages,
   481→          conversationsByCharacter: updatedConversations,
   482→        });
   483→      },
   484→
   485→      clearMessages: () => {
   486→        const state = get();
   487→        const characterId = state.activeCharacter?.id;
   488→
   489→        // Also clear from conversation bucket
   490→        if (characterId) {
   491→          const { [characterId]: _, ...rest } = state.conversationsByCharacter;
   492→          set({ messages: [], conversationsByCharacter: rest });
   493→        } else {
   494→          set({ messages: [] });
   495→        }
   496→      },
   497→
   498→      routeMessage: (message, profile) => {
   499→        const state = get();
   500→        return routeToCharacter({
   501→          message,
   502→          studentProfile: profile,
   503→          currentCharacter: state.activeCharacter
   504→            ? { type: state.activeCharacter.type, id: state.activeCharacter.id }
   505→            : undefined,
   506→          preferContinuity: true,
   507→        });
   508→      },
   509→
   510→      switchToCharacter: (character, type, profile, _reason) => {
   511→        const state = get();
   512→
   513→        // 1. Save current conversation to its bucket
   514→        const savedConversations = saveCurrentConversation(state);
   515→
   516→        // 2. Create new active character
   517→        const activeCharacter = createActiveCharacter(character, type, profile);
   518→
   519→        // 3. Load existing messages for new character (or start fresh)
   520→        let messages = loadConversationMessages(savedConversations, character.id);
   521→
   522→        if (messages.length === 0) {
   523→          // No existing conversation - add greeting
   524→          messages = [
   525→            {
   526→              id: crypto.randomUUID(),
   527→              role: 'assistant',
   528→              content: activeCharacter.greeting,
   529→              timestamp: new Date(),
   530→              characterId: activeCharacter.id,
   531→              characterType: type,
   532→            },
   533→          ];
   534→        }
   535→
   536→        // 4. Update history
   537→        const newHistory = [
   538→          ...state.characterHistory,
   539→          { type, id: character.id, timestamp: new Date() },
   540→        ];
   541→
   542→        set({
   543→          activeCharacter,
   544→          messages,
   545→          characterHistory: newHistory,
   546→          pendingHandoff: null,
   547→          conversationsByCharacter: savedConversations,
   548→        });
   549→      },
   550→
   551→      switchToCoach: (profile) => {
   552→        const coach = getDefaultSupportTeacher();
   553→        get().switchToCharacter(coach, 'coach', profile);
   554→      },
   555→
   556→      switchToMaestro: (maestro, profile) => {
   557→        get().switchToCharacter(maestro, 'maestro', profile);
   558→      },
   559→
   560→      switchToBuddy: (profile) => {
   561→        const buddy = getBuddyForStudent(profile);
   562→        get().switchToCharacter(buddy, 'buddy', profile);
   563→      },
   564→
   565→      goBack: (profile) => {
   566→        const state = get();
   567→        if (state.characterHistory.length <= 1) {
   568→          return false;
   569→        }
   570→
   571→        // Save current before going back
   572→        const savedConversations = saveCurrentConversation(state);
   573→
   574→        const newHistory = state.characterHistory.slice(0, -1);
   575→        const previous = newHistory[newHistory.length - 1];
   576→
   577→        let character: MaestroFull | SupportTeacher | BuddyProfile | undefined;
   578→
   579→        switch (previous.type) {
   580→          case 'maestro':
   581→            character = getMaestroById(previous.id);
   582→            break;
   583→          case 'coach':
   584→            character = getSupportTeacherById(previous.id as 'melissa' | 'roberto');
   585→            break;
   586→          case 'buddy':
   587→            character = getBuddyById(previous.id as BuddyId);
   588→            break;
   589→        }
   590→
   591→        if (!character) {
   592→          return false;
   593→        }
   594→
   595→        const activeCharacter = createActiveCharacter(character, previous.type, profile);
   596→
   597→        // Load that character's messages
   598→        const messages = loadConversationMessages(savedConversations, previous.id);
   599→
   600→        set({
   601→          activeCharacter,
   602→          messages: messages.length > 0 ? messages : [
   603→            {
   604→              id: crypto.randomUUID(),
   605→              role: 'assistant',
   606→              content: activeCharacter.greeting,
   607→              timestamp: new Date(),
   608→              characterId: activeCharacter.id,
   609→              characterType: previous.type,
   610→            },
   611→          ],
   612→          characterHistory: newHistory,
   613→          pendingHandoff: null,
   614→          conversationsByCharacter: savedConversations,
   615→        });
   616→
   617→        return true;
   618→      },
   619→
   620→      suggestHandoff: (suggestion) => {
   621→        set({ pendingHandoff: suggestion });
   622→      },
   623→
   624→      acceptHandoff: (profile) => {
   625→        const state = get();
   626→        if (!state.pendingHandoff) return;
   627→
   628→        const { toCharacter } = state.pendingHandoff;
   629→        get().switchToCharacter(toCharacter.character, toCharacter.type, profile);
   630→      },
   631→
   632→      dismissHandoff: () => {
   633→        set({ pendingHandoff: null });
   634→      },
   635→
   636→      getConversationForCharacter: (characterId) => {
   637→        const state = get();
   638→        return state.conversationsByCharacter[characterId] || null;
   639→      },
   640→
   641→      getAllConversations: () => {
   642→        const state = get();
   643→        return Object.values(state.conversationsByCharacter).sort((a, b) => {
   644→          const aTime = a.lastMessageAt?.getTime() || 0;
   645→          const bTime = b.lastMessageAt?.getTime() || 0;
   646→          return bTime - aTime; // Most recent first
   647→        });
   648→      },
   649→
   650→      reset: () => {
   651→        set({
   652→          mode: 'idle',
   653→          isActive: false,
   654→          activeCharacter: null,
   655→          messages: [],
   656→          pendingHandoff: null,
   657→          conversationsByCharacter: {},
   658→          sessionId: null,
   659→          sessionStartedAt: null,
   660→          characterHistory: [],
   661→        });
   662→      },
   663→
   664→      loadFromServer: async () => {
   665→        try {
   666→          // Load summaries, not full messages
   667→          const summaries = await loadConversationSummariesFromDB();
   668→          if (summaries.length === 0) return;
   669→
   670→          // Convert DB summaries to store format
   671→          const conversationsByCharacter: Record<string, CharacterConversation> = {};
   672→
   673→          for (const conv of summaries) {
   674→            const characterId = conv.maestroId;
   675→
   676→            // Determine character type from ID prefix
   677→            let characterType: CharacterType = 'maestro';
   678→            let characterName = conv.title.replace('Conversazione con ', '');
   679→
   680→            if (characterId.startsWith('coach-')) {
   681→              characterType = 'coach';
   682→              // Extract coach name from ID (e.g., 'coach-melissa' -> 'melissa')
   683→              const coachName = characterId.replace('coach-', '') as CoachId;
   684→              const coach = getSupportTeacherById(coachName);
   685→              if (coach) characterName = coach.name;
   686→            } else if (characterId.startsWith('buddy-')) {
   687→              characterType = 'buddy';
   688→              const buddy = getBuddyById(characterId as BuddyId);
   689→              if (buddy) characterName = buddy.name;
   690→            } else {
   691→              const maestro = getMaestroById(characterId);
   692→              if (maestro) characterName = maestro.name;
   693→            }
   694→
   695→            // Store summary for context, not full messages
   696→            conversationsByCharacter[characterId] = {
   697→              characterId,
   698→              characterType,
   699→              characterName,
   700→              messages: [], // Start fresh, use summary for context
   701→              lastMessageAt: conv.lastMessageAt ? new Date(conv.lastMessageAt) : null,
   702→              conversationId: conv.id,
   703→              previousSummary: conv.summary || undefined,
   704→              previousKeyFacts: conv.keyFacts || undefined,
   705→              previousTopics: conv.topics || undefined,
   706→            };
   707→          }
   708→
   709→          set({ conversationsByCharacter });
   710→          logger.info('Loaded conversation summaries from server', {
   711→            count: Object.keys(conversationsByCharacter).length,
   712→          });
   713→        } catch (error) {
   714→          // Non-critical: app works fine without previous conversation context
   715→          logger.warn('Failed to load conversation summaries', {
   716→            error: error instanceof Error ? error.message : String(error),
   717→          });
   718→        }
   719→      },
   720→    })
   721→);
   722→

