   185→        set({ voiceBargeInEnabled: enabled, pendingSync: true }),
   186→
   187→      syncToServer: async () => {
   188→        const state = get();
   189→        if (!state.pendingSync) return;
   190→
   191→        try {
   192→          // Sync settings
   193→          await fetch('/api/user/settings', {
   194→            method: 'PUT',
   195→            headers: { 'Content-Type': 'application/json' },
   196→            body: JSON.stringify({
   197→              theme: state.theme,
