   224→                voiceEnabled: state.studentProfile.voiceEnabled,
   225→                simplifiedLanguage: state.studentProfile.simplifiedLanguage,
   226→                adhdMode: state.studentProfile.adhdMode,
   227→              },
   228→            }),
   229→          });
   230→
   231→          set({ lastSyncedAt: new Date(), pendingSync: false });
   232→        } catch (error) {
   233→          logger.error('Settings sync failed', { error: String(error) });
   234→        }
   235→      },
   236→
   237→      loadFromServer: async () => {
   238→        try {
   239→          const [settingsRes, profileRes] = await Promise.all([
   240→            fetch('/api/user/settings'),
   241→            fetch('/api/user/profile'),
   242→          ]);
   243→
   244→          if (settingsRes.ok) {
   245→            const settings = await settingsRes.json();
   246→            set((state) => ({
   247→              theme: settings.theme ?? state.theme,
   248→              provider: settings.provider ?? state.provider,
