   250→              budgetLimit: settings.budgetLimit ?? state.budgetLimit,
   251→              appearance: {
   252→                ...state.appearance,
   253→                language: settings.language ?? state.appearance.language,
   254→                accentColor: settings.accentColor ?? state.appearance.accentColor,
   255→              },
   256→            }));
   257→          }
   258→
   259→          if (profileRes.ok) {
   260→            const profile = await profileRes.json();
   261→            if (profile) {
   262→              const accessibility = profile.accessibility || {};
   263→              set((state) => ({
   264→                studentProfile: {
   265→                  ...state.studentProfile,
   266→                  name: profile.name ?? state.studentProfile.name,
   267→                  age: profile.age ?? state.studentProfile.age,
   268→                  schoolYear: profile.schoolYear ?? state.studentProfile.schoolYear,
   269→                  schoolLevel: profile.schoolLevel ?? state.studentProfile.schoolLevel,
   270→                  gradeLevel: profile.gradeLevel ?? state.studentProfile.gradeLevel,
   271→                  learningGoals: profile.learningGoals ?? state.studentProfile.learningGoals,
   272→                  // Character preferences
   273→                  preferredCoach: profile.preferredCoach ?? state.studentProfile.preferredCoach,
   274→                  preferredBuddy: profile.preferredBuddy ?? state.studentProfile.preferredBuddy,
   275→                  fontSize: accessibility.fontSize ?? state.studentProfile.fontSize,
   276→                  highContrast: accessibility.highContrast ?? state.studentProfile.highContrast,
   277→                  dyslexiaFont: accessibility.dyslexiaFont ?? state.studentProfile.dyslexiaFont,
   278→                  voiceEnabled: accessibility.voiceEnabled ?? state.studentProfile.voiceEnabled,
   279→                  simplifiedLanguage: accessibility.simplifiedLanguage ?? state.studentProfile.simplifiedLanguage,
   280→                  adhdMode: accessibility.adhdMode ?? state.studentProfile.adhdMode,
   281→                },
   282→              }));
   283→            }
