   294→// === PROGRESS STORE (Gamification) ===
   295→
   296→// Session grade given by maestro (1-10 scale)
   297→export interface SessionGrade {
   298→  score: number; // 1-10
   299→  feedback: string;
   300→  strengths: string[];
   301→  areasToImprove: string[];
   302→}
   303→
   304→interface StudySession {
   305→  id: string;
   306→  maestroId: string;
   307→  subject: string;
   308→  startedAt: Date;
   309→  endedAt?: Date;
   310→  durationMinutes?: number;
   311→  questionsAsked: number;
   312→  xpEarned: number;
   313→  grade?: SessionGrade; // Grade given by maestro at end of session
   314→}
   315→
   316→interface ProgressState {
   317→  xp: number;
   318→  level: number;
   319→  streak: Streak;
   320→  masteries: SubjectMastery[];
   321→  achievements: Achievement[];
   322→  totalStudyMinutes: number;
   323→  sessionsThisWeek: number;
   324→  questionsAsked: number;
   325→  // Session tracking
   326→  currentSession: StudySession | null;
   327→  sessionHistory: StudySession[];
   328→  // Sync state
   329→  lastSyncedAt: Date | null;
   330→  pendingSync: boolean;
   331→  // Actions
   332→  addXP: (amount: number) => void;
   333→  updateStreak: () => void;
   334→  updateMastery: (subjectMastery: SubjectMastery) => void;
   335→  unlockAchievement: (achievementId: string) => void;
   336→  addStudyMinutes: (minutes: number) => void;
   337→  incrementQuestions: () => void;
   338→  // Session actions
   339→  startSession: (maestroId: string, subject: string) => void;
   340→  endSession: (grade?: SessionGrade) => void;
   341→  gradeCurrentSession: (grade: SessionGrade) => void;
   342→  // Sync actions
   343→  syncToServer: () => Promise<void>;
   344→  loadFromServer: () => Promise<void>;
   345→}
   346→
   347→const XP_PER_LEVEL = [
   348→  0, 100, 250, 500, 1000, 2000, 4000, 8000, 16000, 32000, 64000,
   349→];
   350→
   351→export const useProgressStore = create<ProgressState>()(
   352→  (set, get) => ({
   353→      xp: 0,
   354→      level: 1,
   355→      streak: { current: 0, longest: 0 },
   356→      masteries: [],
   357→      achievements: [],
   358→      totalStudyMinutes: 0,
   359→      sessionsThisWeek: 0,
   360→      questionsAsked: 0,
   361→      currentSession: null,
   362→      sessionHistory: [],
   363→      lastSyncedAt: null,
   364→      pendingSync: false,
   365→
   366→      addXP: (amount) =>
   367→        set((state) => {
   368→          const newXP = state.xp + amount;
   369→          let newLevel = state.level;
   370→          while (
   371→            newLevel < XP_PER_LEVEL.length - 1 &&
   372→            newXP >= XP_PER_LEVEL[newLevel]
   373→          ) {
   374→            newLevel++;
   375→          }
   376→          // Trigger level up notification if level increased
   377→          if (newLevel > state.level) {
   378→            const levelTitles: Record<number, string> = {
   379→              1: 'Principiante',
   380→              2: 'Apprendista',
   381→              3: 'Studente',
   382→              4: 'Studioso',
   383→              5: 'Esperto',
   384→              6: 'Professore',
   385→              7: 'Gran Professore',
   386→              8: 'Saggio',
   387→              9: 'Illuminato',
   388→              10: 'Leggenda',
   389→            };
   390→            onLevelUp(newLevel, levelTitles[newLevel] || `Livello ${newLevel}`);
   391→          }
   392→          // Update current session XP
   393→          const updatedSession = state.currentSession
   394→            ? { ...state.currentSession, xpEarned: state.currentSession.xpEarned + amount }
   395→            : null;
   396→          return { xp: newXP, level: newLevel, currentSession: updatedSession, pendingSync: true };
   397→        }),
   398→
   399→      updateStreak: () =>
   400→        set((state) => {
   401→          const today = new Date().toDateString();
   402→          const lastStudy = state.streak.lastStudyDate;
   403→          const yesterday = new Date(Date.now() - 86400000).toDateString();
   404→
   405→          let newCurrent = state.streak.current;
   406→          if (!lastStudy || new Date(lastStudy).toDateString() !== today) {
   407→            if (lastStudy && new Date(lastStudy).toDateString() === yesterday) {
   408→              newCurrent++;
   409→            } else if (!lastStudy || new Date(lastStudy).toDateString() !== yesterday) {
   410→              newCurrent = 1;
   411→            }
   412→          }
   413→
   414→          // Trigger streak milestone notification if applicable
   415→          if (newCurrent > state.streak.current) {
   416→            onStreakMilestone(newCurrent);
   417→          }
   418→
   419→          return {
   420→            streak: {
   421→              current: newCurrent,
   422→              longest: Math.max(state.streak.longest, newCurrent),
   423→              lastStudyDate: new Date(),
   424→            },
   425→            pendingSync: true,
   426→          };
   427→        }),
   428→
   429→      updateMastery: (subjectMastery) =>
   430→        set((state) => {
   431→          const existing = state.masteries.findIndex(
   432→            (m) => m.subject === subjectMastery.subject
   433→          );
   434→          if (existing >= 0) {
   435→            const newMasteries = [...state.masteries];
   436→            newMasteries[existing] = subjectMastery;
   437→            return { masteries: newMasteries, pendingSync: true };
   438→          }
   439→          return { masteries: [...state.masteries, subjectMastery], pendingSync: true };
   440→        }),
   441→
   442→      unlockAchievement: (achievementId) =>
   443→        set((state) => {
   444→          const achievement = state.achievements.find(
   445→            (a) => a.id === achievementId
   446→          );
   447→          if (achievement && !achievement.unlockedAt) {
   448→            // Trigger achievement notification
   449→            onAchievement(achievement.name, achievement.description);
   450→            return {
   451→              achievements: state.achievements.map((a) =>
   452→                a.id === achievementId ? { ...a, unlockedAt: new Date() } : a
   453→              ),
   454→              pendingSync: true,
   455→            };
   456→          }
   457→          return state;
   458→        }),
   459→
   460→      addStudyMinutes: (minutes) =>
   461→        set((state) => ({
   462→          totalStudyMinutes: state.totalStudyMinutes + minutes,
   463→          pendingSync: true,
   464→        })),
   465→
   466→      incrementQuestions: () =>
   467→        set((state) => {
   468→          const updatedSession = state.currentSession
   469→            ? { ...state.currentSession, questionsAsked: state.currentSession.questionsAsked + 1 }
   470→            : null;
   471→          return {
   472→            questionsAsked: state.questionsAsked + 1,
   473→            currentSession: updatedSession,
   474→            pendingSync: true,
   475→          };
   476→        }),
   477→
   478→      startSession: (maestroId, subject) =>
   479→        set((state) => {
   480→          // End any existing session first
   481→          if (state.currentSession) {
   482→            const endedSession = {
   483→              ...state.currentSession,
   484→              endedAt: new Date(),
   485→              durationMinutes: Math.round(
   486→                (Date.now() - new Date(state.currentSession.startedAt).getTime()) / 60000
   487→              ),
   488→            };
   489→            return {
   490→              currentSession: {
   491→                id: crypto.randomUUID(),
   492→                maestroId,
   493→                subject,
   494→                startedAt: new Date(),
   495→                questionsAsked: 0,
   496→                xpEarned: 0,
   497→              },
   498→              sessionHistory: [endedSession, ...state.sessionHistory].slice(0, 100),
   499→              pendingSync: true,
   500→            };
   501→          }
   502→          return {
   503→            currentSession: {
   504→              id: crypto.randomUUID(),
   505→              maestroId,
   506→              subject,
   507→              startedAt: new Date(),
   508→              questionsAsked: 0,
   509→              xpEarned: 0,
   510→            },
   511→            pendingSync: true,
   512→          };
   513→        }),
   514→
   515→      endSession: (grade) =>
   516→        set((state) => {
   517→          if (!state.currentSession) return state;
   518→
   519→          const durationMinutes = Math.round(
   520→            (Date.now() - new Date(state.currentSession.startedAt).getTime()) / 60000
   521→          );
   522→          const endedSession = {
   523→            ...state.currentSession,
   524→            endedAt: new Date(),
   525→            durationMinutes,
   526→            grade: grade || state.currentSession.grade,
   527→          };
   528→
   529→          // Calculate week sessions
   530→          const weekAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000);
   531→          const recentSessions = [endedSession, ...state.sessionHistory].filter(
   532→            (s) => new Date(s.startedAt) > weekAgo
   533→          );
   534→
   535→          return {
   536→            currentSession: null,
   537→            sessionHistory: [endedSession, ...state.sessionHistory].slice(0, 100),
   538→            totalStudyMinutes: state.totalStudyMinutes + durationMinutes,
   539→            sessionsThisWeek: recentSessions.length,
   540→            pendingSync: true,
   541→          };
   542→        }),
   543→
   544→      gradeCurrentSession: (grade) =>
   545→        set((state) => {
   546→          if (!state.currentSession) return state;
   547→          return {
   548→            currentSession: { ...state.currentSession, grade },
   549→            pendingSync: true,
   550→          };
   551→        }),
   552→
   553→      syncToServer: async () => {
   554→        const state = get();
   555→        if (!state.pendingSync) return;
   556→
   557→        try {
   558→          // Sync main progress
   559→          await fetch('/api/progress', {
   560→            method: 'PUT',
   561→            headers: { 'Content-Type': 'application/json' },
   562→            body: JSON.stringify({
   563→              xp: state.xp,
   564→              level: state.level,
   565→              streak: state.streak,
   566→              totalStudyMinutes: state.totalStudyMinutes,
   567→              questionsAsked: state.questionsAsked,
   568→              masteries: state.masteries,
   569→              achievements: state.achievements,
   570→            }),
   571→          });
   572→
   573→          // Sync recent sessions
   574→          const unsyncedSessions = state.sessionHistory.filter(
   575→            (s) => s.endedAt && !s.id.startsWith('synced-')
   576→          ).slice(0, 10);
   577→
   578→          for (const session of unsyncedSessions) {
   579→            await fetch('/api/progress/sessions', {
   580→              method: 'POST',
   581→              headers: { 'Content-Type': 'application/json' },
   582→              body: JSON.stringify(session),
   583→            });
   584→          }
   585→
   586→          set({ lastSyncedAt: new Date(), pendingSync: false });
   587→        } catch (error) {
   588→          logger.error('Progress sync failed', { error: String(error) });
   589→        }
   590→      },
   591→
   592→      loadFromServer: async () => {
   593→        try {
   594→          const [progressRes, sessionsRes] = await Promise.all([
   595→            fetch('/api/progress'),
   596→            fetch('/api/progress/sessions?limit=20'),
   597→          ]);
   598→
   599→          if (progressRes.ok) {
   600→            const data = await progressRes.json();
   601→            set((state) => ({
   602→              xp: data.xp ?? state.xp,
   603→              level: data.level ?? state.level,
   604→              streak: data.streak ?? state.streak,
   605→              masteries: data.masteries ?? state.masteries,
   606→              achievements: data.achievements ?? state.achievements,
   607→              totalStudyMinutes: data.totalStudyMinutes ?? state.totalStudyMinutes,
   608→              questionsAsked: data.questionsAsked ?? state.questionsAsked,
   609→            }));
   610→          }
   611→
   612→          if (sessionsRes.ok) {
   613→            const sessions = await sessionsRes.json();
   614→            if (Array.isArray(sessions)) {
   615→              // Calculate sessionsThisWeek from DB sessions
   616→              const weekAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000);
   617→              const recentCount = sessions.filter(
   618→                (s: StudySession) => new Date(s.startedAt) > weekAgo
   619→              ).length;
   620→
   621→              set({
   622→                sessionHistory: sessions.map((s: StudySession) => ({
   623→                  ...s,
   624→                  id: `synced-${s.id}`, // Mark as synced
   625→                  startedAt: new Date(s.startedAt),
   626→                  endedAt: s.endedAt ? new Date(s.endedAt) : undefined,
   627→                })),
   628→                sessionsThisWeek: recentCount,
   629→              });
   630→            }
   631→          }
   632→
   633→          set({ lastSyncedAt: new Date(), pendingSync: false });
   634→        } catch (error) {
   635→          logger.error('Progress load failed', { error: String(error) });
   636→        }
   637→      },
   638→    })
   639→);
