   733→  loadFromServer: () => Promise<void>;
   734→}
   735→
   736→export const useConversationStore = create<ConversationState>()(
   737→  (set) => ({
   738→      conversations: [],
   739→      currentConversationId: null,
   740→      lastSyncedAt: null,
   741→      pendingSync: false,
   742→
   743→      createConversation: async (maestroId) => {
   744→        const tempId = crypto.randomUUID();
   745→        const conversation: Conversation = {
   746→          id: tempId,
   747→          title: 'New Conversation',
   748→          messages: [],
   749→          maestroId,
   750→          createdAt: new Date(),
   751→          updatedAt: new Date(),
   752→        };
   753→
   754→        // Optimistic update
   755→        set((state) => ({
   756→          conversations: [conversation, ...state.conversations],
   757→          currentConversationId: tempId,
   758→        }));
   759→
   760→        // Sync to server
   761→        try {
   762→          const response = await fetch('/api/conversations', {
   763→            method: 'POST',
   764→            headers: { 'Content-Type': 'application/json' },
   765→            body: JSON.stringify({ maestroId }),
   766→          });
   767→
   768→          if (response.ok) {
   769→            const serverConv = await response.json();
   770→            // Update with server ID
   771→            set((state) => ({
   772→              conversations: state.conversations.map((c) =>
   773→                c.id === tempId ? { ...c, id: serverConv.id } : c
   774→              ),
   775→              currentConversationId:
   776→                state.currentConversationId === tempId
   777→                  ? serverConv.id
   778→                  : state.currentConversationId,
   779→            }));
   780→            return serverConv.id;
   781→          }
   782→        } catch (error) {
   783→          logger.error('Failed to create conversation on server', { error: String(error) });
   784→        }
   785→
   786→        return tempId;
   787→      },
   788→
   789→      addMessage: async (conversationId, message) => {
   790→        const messageWithId = {
   791→          ...message,
   792→          id: crypto.randomUUID(),
   793→          timestamp: new Date(),
   794→        };
   795→
   796→        // Optimistic update
   797→        set((state) => ({
   798→          conversations: state.conversations.map((conv) =>
   799→            conv.id === conversationId
   800→              ? {
   801→                  ...conv,
   802→                  messages: [...conv.messages, messageWithId],
   803→                  updatedAt: new Date(),
   804→                  title:
   805→                    conv.messages.length === 0 && message.role === 'user'
   806→                      ? message.content.slice(0, 50)
   807→                      : conv.title,
   808→                }
   809→              : conv
   810→          ),
   811→          pendingSync: true,
   812→        }));
   813→
   814→        // Sync to server
   815→        try {
   816→          await fetch(`/api/conversations/${conversationId}/messages`, {
   817→            method: 'POST',
   818→            headers: { 'Content-Type': 'application/json' },
   819→            body: JSON.stringify({
   820→              role: message.role,
   821→              content: message.content,
   822→              toolCalls: (message as { toolCalls?: unknown }).toolCalls,
   823→            }),
   824→          });
   825→        } catch (error) {
   826→          logger.error('Failed to add message to server', { error: String(error) });
   827→        }
   828→      },
   829→
   830→      setCurrentConversation: (id) => set({ currentConversationId: id }),
   831→
   832→      deleteConversation: async (id) => {
   833→        // Optimistic update
   834→        set((state) => ({
   835→          conversations: state.conversations.filter((c) => c.id !== id),
   836→          currentConversationId:
   837→            state.currentConversationId === id
   838→              ? null
   839→              : state.currentConversationId,
   840→        }));
   841→
   842→        // Sync to server
   843→        try {
   844→          await fetch(`/api/conversations/${id}`, { method: 'DELETE' });
   845→        } catch (error) {
   846→          logger.error('Failed to delete conversation on server', { error: String(error) });
   847→        }
   848→      },
   849→
   850→      clearConversations: () =>
   851→        set({ conversations: [], currentConversationId: null }),
   852→
   853→      syncToServer: async () => {
   854→        // Conversations are synced immediately on each action
   855→        set({ lastSyncedAt: new Date(), pendingSync: false });
   856→      },
   857→
   858→      loadFromServer: async () => {
   859→        try {
   860→          const response = await fetch('/api/conversations?limit=50');
   861→          if (response.ok) {
   862→            const conversations = await response.json();
   863→            set({
   864→              conversations: conversations.map((c: {
   865→                id: string;
   866→                title: string;
   867→                maestroId: string;
   868→                createdAt: string;
   869→                updatedAt: string;
   870→                lastMessage?: string;
   871→              }) => ({
   872→                ...c,
   873→                messages: [], // Messages are loaded on-demand
   874→                createdAt: new Date(c.createdAt),
   875→                updatedAt: new Date(c.updatedAt),
   876→              })),
   877→              lastSyncedAt: new Date(),
   878→              pendingSync: false,
   879→            });
   880→          }
   881→        } catch (error) {
   882→          logger.error('Conversations load failed', { error: String(error) });
   883→        }
   884→      },
   885→    })
   886→);
   887→
   888→// === LEARNINGS STORE ===
   889→
   890→interface Learning {
   891→  id: string;
   892→  category: 'preference' | 'strength' | 'weakness' | 'interest' | 'style';
   893→  insight: string;
   894→  maestroId?: string;
   895→  subject?: string;
   896→  confidence: number;
   897→  occurrences: number;
