   899→  updatedAt: Date;
   900→}
   901→
   902→interface LearningsState {
   903→  learnings: Learning[];
   904→  lastSyncedAt: Date | null;
   905→  // Actions
   906→  addLearning: (learning: Omit<Learning, 'id' | 'occurrences' | 'createdAt' | 'updatedAt'>) => Promise<void>;
   907→  removeLearning: (id: string) => Promise<void>;
   908→  getLearningsByCategory: (category: Learning['category']) => Learning[];
   909→  // Sync
   910→  loadFromServer: () => Promise<void>;
   911→}
   912→
   913→export const useLearningsStore = create<LearningsState>()(
   914→  (set, get) => ({
   915→      learnings: [],
   916→      lastSyncedAt: null,
   917→
   918→      addLearning: async (learning) => {
   919→        try {
   920→          const response = await fetch('/api/learnings', {
   921→            method: 'POST',
   922→            headers: { 'Content-Type': 'application/json' },
   923→            body: JSON.stringify(learning),
   924→          });
   925→
   926→          if (response.ok) {
   927→            const serverLearning = await response.json();
   928→            set((state) => {
   929→              // Check if this was a reinforcement
   930→              if (serverLearning.reinforced) {
   931→                return {
   932→                  learnings: state.learnings.map((l) =>
   933→                    l.id === serverLearning.id
   934→                      ? { ...l, confidence: serverLearning.confidence, occurrences: serverLearning.occurrences }
   935→                      : l
   936→                  ),
   937→                };
   938→              }
   939→              // New learning
   940→              return {
   941→                learnings: [
   942→                  {
   943→                    ...serverLearning,
   944→                    createdAt: new Date(serverLearning.createdAt),
   945→                    updatedAt: new Date(serverLearning.updatedAt),
   946→                  },
   947→                  ...state.learnings,
   948→                ],
   949→              };
   950→            });
   951→          }
   952→        } catch (error) {
   953→          logger.error('Failed to add learning', { error: String(error) });
   954→        }
   955→      },
   956→
   957→      removeLearning: async (id) => {
   958→        set((state) => ({
