   966→        }
   967→      },
   968→
   969→      getLearningsByCategory: (category) => {
   970→        return get().learnings.filter((l) => l.category === category);
   971→      },
   972→
   973→      loadFromServer: async () => {
   974→        try {
   975→          const response = await fetch('/api/learnings');
