   987→        } catch (error) {
   988→          logger.error('Learnings load failed', { error: String(error) });
   989→        }
   990→      },
   991→    })
   992→);
   993→
   994→// === HTML SNIPPETS STORE ===
   995→
   996→export interface HTMLSnippet {
