  1088→
  1089→// Subject to Maestro ID mapping
  1090→const SUBJECT_TO_MAESTRO: Record<string, string> = {
  1091→  mathematics: 'euclide-matematica',
  1092→  math: 'euclide-matematica',
  1093→  matematica: 'euclide-matematica',
  1094→  history: 'clio-storia',
  1095→  storia: 'clio-storia',
