  1123→
  1124→export const useCalendarStore = create<CalendarState>()(
  1125→  (set, get) => ({
  1126→      events: [],
  1127→
  1128→      addEvent: (event) =>
  1129→        set((state) => {
  1130→          const subjectLower = event.subject.toLowerCase();
  1131→          const maestroId = SUBJECT_TO_MAESTRO[subjectLower];
  1132→          return {
  1133→            events: [
  1134→              ...state.events,
  1135→              {
  1136→                ...event,
  1137→                id: crypto.randomUUID(),
  1138→                completed: false,
  1139→                maestroSuggested: maestroId,
  1140→              },
  1141→            ],
  1142→          };
  1143→        }),
  1144→
  1145→      updateEvent: (id, updates) =>
  1146→        set((state) => ({
  1147→          events: state.events.map((e) =>
  1148→            e.id === id ? { ...e, ...updates } : e
  1149→          ),
  1150→        })),
  1151→
  1152→      deleteEvent: (id) =>
  1153→        set((state) => ({
