  1155→        })),
  1156→
  1157→      toggleCompleted: (id) =>
  1158→        set((state) => ({
  1159→          events: state.events.map((e) =>
  1160→            e.id === id ? { ...e, completed: !e.completed } : e
  1161→          ),
  1162→        })),
  1163→
  1164→      getUpcomingEvents: (days) => {
  1165→        const now = new Date();
  1166→        const future = new Date(now.getTime() + days * 24 * 60 * 60 * 1000);
  1167→        return get()
  1168→          .events.filter(
  1169→            (e) => !e.completed && new Date(e.date) >= now && new Date(e.date) <= future
  1170→          )
  1171→          .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());
  1172→      },
  1173→
  1174→      getEventsBySubject: (subject) => {
  1175→        return get().events.filter(
  1176→          (e) => e.subject.toLowerCase() === subject.toLowerCase()
  1177→        );
  1178→      },
  1179→
  1180→      getSuggestedMaestri: () => {
  1181→        const upcoming = get().getUpcomingEvents(7);
  1182→        const suggestions: Map<string, { count: number; nearestDays: number; types: Set<string> }> = new Map();
  1183→
  1184→        const now = new Date();
  1185→        upcoming.forEach((event) => {
  1186→          const maestroId = event.maestroSuggested;
  1187→          if (!maestroId) return;
  1188→
  1189→          const daysUntil = Math.ceil(
  1190→            (new Date(event.date).getTime() - now.getTime()) / (24 * 60 * 60 * 1000)
  1191→          );
  1192→
  1193→          if (suggestions.has(maestroId)) {
  1194→            const existing = suggestions.get(maestroId)!;
  1195→            existing.count++;
  1196→            existing.nearestDays = Math.min(existing.nearestDays, daysUntil);
  1197→            existing.types.add(event.type);
  1198→          } else {
  1199→            suggestions.set(maestroId, {
  1200→              count: 1,
  1201→              nearestDays: daysUntil,
  1202→              types: new Set([event.type]),
  1203→            });
  1204→          }
  1205→        });
  1206→
  1207→        return Array.from(suggestions.entries())
  1208→          .map(([maestroId, data]) => {
  1209→            let priority: 'high' | 'medium' | 'low' = 'low';
  1210→            let reason = '';
  1211→
  1212→            if (data.nearestDays <= 1) {
  1213→              priority = 'high';
  1214→              reason = data.types.has('exam') || data.types.has('test')
  1215→                ? 'Test tomorrow - review now!'
  1216→                : 'Event tomorrow';
  1217→            } else if (data.nearestDays <= 3) {
  1218→              priority = 'high';
  1219→              reason = `${data.count} event${data.count > 1 ? 's' : ''} in ${data.nearestDays} days`;
  1220→            } else if (data.nearestDays <= 5) {
  1221→              priority = 'medium';
  1222→              reason = `Prepare for upcoming ${Array.from(data.types).join('/')}`;
  1223→            } else {
  1224→              priority = 'low';
  1225→              reason = `${data.count} event${data.count > 1 ? 's' : ''} this week`;
  1226→            }
  1227→
  1228→            return { maestroId, reason, priority };
  1229→          })
  1230→          .sort((a, b) => {
  1231→            const priorityOrder = { high: 0, medium: 1, low: 2 };
  1232→            return priorityOrder[a.priority] - priorityOrder[b.priority];
  1233→          });
  1234→      },
  1235→    })
  1236→);
  1237→
  1238→// === UI STORE ===
  1239→
  1240→interface UIState {
  1241→  sidebarOpen: boolean;
