  1244→  // Focus Mode - fullscreen tool view
  1245→  focusMode: boolean;
  1246→  focusTool: ToolState | null;
  1247→  focusToolType: ToolType | null;
  1248→  focusMaestroId: string | null;
  1249→  // Actions
  1250→  toggleSidebar: () => void;
  1251→  setSidebarOpen: (open: boolean) => void;
  1252→  toggleSettings: () => void;
  1253→  setCurrentView: (view: UIState['currentView']) => void;
  1254→  // Focus Mode Actions
  1255→  enterFocusMode: (toolType: ToolType, maestroId?: string) => void;
  1256→  setFocusTool: (tool: ToolState | null) => void;
  1257→  exitFocusMode: () => void;
  1258→}
  1259→
  1260→export const useUIStore = create<UIState>((set) => ({
  1261→  sidebarOpen: true,
  1262→  settingsOpen: false,
  1263→  currentView: 'maestri',
  1264→  focusMode: false,
  1265→  focusTool: null,
  1266→  focusToolType: null,
  1267→  focusMaestroId: null,
  1268→  toggleSidebar: () => set((state) => ({ sidebarOpen: !state.sidebarOpen })),
  1269→  setSidebarOpen: (sidebarOpen) => set({ sidebarOpen }),
  1270→  toggleSettings: () => set((state) => ({ settingsOpen: !state.settingsOpen })),
  1271→  setCurrentView: (currentView) => set({ currentView }),
  1272→  enterFocusMode: (toolType, maestroId) => set({
  1273→    focusMode: true,
  1274→    focusToolType: toolType,
  1275→    focusMaestroId: maestroId || null,
  1276→    focusTool: null, // Will be set when tool is created
  1277→  }),
  1278→  setFocusTool: (tool) => set({ focusTool: tool }),
  1279→  exitFocusMode: () => set({
  1280→    focusMode: false,
  1281→    focusTool: null,
  1282→    focusToolType: null,
  1283→    focusMaestroId: null,
  1284→  }),
  1285→}));
  1286→
  1287→// === SYNC HOOK ===
  1288→
  1289→export async function initializeStores() {
  1290→  // Ensure user exists (creates cookie if needed)
  1291→  await fetch('/api/user');
  1292→
  1293→  // Load data from server
  1294→  await Promise.all([
  1295→    useSettingsStore.getState().loadFromServer(),
  1296→    useProgressStore.getState().loadFromServer(),
  1297→    useConversationStore.getState().loadFromServer(),
  1298→    useLearningsStore.getState().loadFromServer(),
  1299→  ]);
  1300→}
  1301→
  1302→export function setupAutoSync(intervalMs = 30000) {
  1303→  // Auto-sync every 30 seconds if there are pending changes
  1304→  return setInterval(async () => {
  1305→    const settings = useSettingsStore.getState();
  1306→    const progress = useProgressStore.getState();
  1307→
  1308→    if (settings.pendingSync) {
  1309→      await settings.syncToServer();
  1310→    }
  1311→    if (progress.pendingSync) {
  1312→      await progress.syncToServer();
  1313→    }
