// ============================================================================
// CONVERGIO WEB - MAIN APPLICATION STORE (Zustand)
// With database sync via API routes
// ============================================================================

import { create } from 'zustand';
import { logger } from '@/lib/logger';
import { onLevelUp, onStreakMilestone, onAchievement } from '@/lib/notifications/triggers';
import type {
  Maestro,
  Theme,
  AIProvider,
  Streak,
  Achievement,
  SubjectMastery,
  Conversation,
  ChatMessage,
  ToolCall,
} from '@/types';
import type { ToolState, ToolType } from '@/types/tools';

// === SETTINGS STORE ===

interface AppearanceSettings {
  theme: 'light' | 'dark' | 'system';
  accentColor: string;
  language: 'it' | 'en' | 'es' | 'fr' | 'de';
}

// Teaching style from super encouraging to brutal
export type TeachingStyle = 'super_encouraging' | 'encouraging' | 'balanced' | 'strict' | 'brutal';

/**
 * Learning differences that the platform supports.
 * Used for buddy matching and accessibility features.
 */
export type LearningDifference =
  | 'dyslexia'
  | 'dyscalculia'
  | 'dysgraphia'
  | 'adhd'
  | 'autism'
  | 'cerebralPalsy'
  | 'visualImpairment'
  | 'auditoryProcessing';

interface ExtendedStudentProfile {
  name: string;
  age: number;
  schoolYear: number;
  schoolLevel: 'elementare' | 'media' | 'superiore';
  gradeLevel: string;
  learningGoals: string[];
  teachingStyle: TeachingStyle;
  fontSize: 'small' | 'medium' | 'large' | 'extra-large';
  highContrast: boolean;
  dyslexiaFont: boolean;
  voiceEnabled: boolean;
  simplifiedLanguage: boolean;
  adhdMode: boolean;
  // MirrorBuddy character preferences
  learningDifferences: LearningDifference[];
  preferredCoach?: 'melissa' | 'roberto' | 'chiara' | 'andrea' | 'favij';
  preferredBuddy?: 'mario' | 'noemi' | 'enea' | 'bruno' | 'sofia';
  // Custom border colors for coach and buddy avatars
  coachBorderColor?: string;
  buddyBorderColor?: string;
}

// Provider preference for manual selection
export type ProviderPreference = 'azure' | 'ollama' | 'auto';

interface SettingsState {
  theme: Theme;
  provider: AIProvider;
  model: string;
  budgetLimit: number;
  totalSpent: number;
  studentProfile: ExtendedStudentProfile;
  appearance: AppearanceSettings;
  preferredProvider: ProviderPreference;
  preferredMicrophoneId: string; // Empty string = system default
  preferredOutputId: string; // Empty string = system default (speakers)
  preferredCameraId: string; // Empty string = system default
  // Voice settings (Azure Realtime API)
  voiceVadThreshold: number; // VAD sensitivity (0.3-0.7, default 0.4)
  voiceSilenceDuration: number; // Silence before turn ends (300-800ms, default 400)
  voiceBargeInEnabled: boolean; // Allow interrupting maestro (default true)
  // Sync state
  lastSyncedAt: Date | null;
  pendingSync: boolean;
  // Actions
  setTheme: (theme: Theme) => void;
  setProvider: (provider: AIProvider) => void;
  setModel: (model: string) => void;
  setBudgetLimit: (limit: number) => void;
  addCost: (cost: number) => void;
  updateStudentProfile: (profile: Partial<ExtendedStudentProfile>) => void;
  updateAppearance: (appearance: Partial<AppearanceSettings>) => void;
  setPreferredProvider: (provider: ProviderPreference) => void;
  setPreferredMicrophone: (microphoneId: string) => void;
  setPreferredOutput: (outputId: string) => void;
  setPreferredCamera: (cameraId: string) => void;
  // Voice settings actions
