     1→// ============================================================================
     2→// LLM SUMMARIZATION & LEARNING EXTRACTION
     3→// Used to compress conversations and extract user insights
     4→// ============================================================================
     5→
     6→import { chatCompletion, getActiveProvider } from './providers';
     7→import { logger } from '@/lib/logger';
     8→
     9→interface Message {
    10→  role: string;
    11→  content: string;
    12→}
    13→
    14→interface KeyFacts {
    15→  decisions: string[];
    16→  preferences: string[];
    17→  learned: string[];
    18→}
    19→
    20→interface Learning {
    21→  category: 'preference' | 'strength' | 'weakness' | 'interest' | 'style';
    22→  insight: string;
    23→  confidence: number;
    24→}
    25→
    26→/**
    27→ * Generate a summary of conversation messages
    28→ * Used when conversation gets too long to maintain context
    29→ */
    30→export async function generateConversationSummary(
    31→  messages: Message[]
    32→): Promise<string> {
    33→  const provider = getActiveProvider();
    34→  if (!provider) {
    35→    throw new Error('No AI provider available for summarization');
    36→  }
    37→
    38→  const systemPrompt = `Sei un assistente che riassume conversazioni educative.
    39→Crea un riassunto conciso che catturi:
    40→- Argomenti principali discussi
    41→- Domande chiave dello studente
    42→- Concetti spiegati
    43→- Eventuali difficoltà emerse
    44→
    45→Rispondi in italiano, max 200 parole.
    46→Usa un linguaggio chiaro e diretto.`;
    47→
    48→  const userPrompt = `Riassumi questa conversazione:
    49→
    50→${messages.map((m) => `${m.role === 'user' ? 'STUDENTE' : 'MAESTRO'}: ${m.content}`).join('\n\n')}`;
    51→
    52→  const result = await chatCompletion(
    53→    [{ role: 'user', content: userPrompt }],
    54→    systemPrompt
    55→  );
    56→
    57→  return result.content;
    58→}
    59→
    60→/**
    61→ * Extract key facts from conversation
    62→ * Identifies decisions, preferences, and what was learned
    63→ */
    64→export async function extractKeyFacts(messages: Message[]): Promise<KeyFacts> {
    65→  const provider = getActiveProvider();
    66→  if (!provider) {
    67→    return { decisions: [], preferences: [], learned: [] };
    68→  }
    69→
    70→  const systemPrompt = `Estrai informazioni chiave dalla conversazione educativa in formato JSON.
    71→
    72→Rispondi SOLO con JSON valido in questo formato:
    73→{
    74→  "decisions": ["decisioni prese dallo studente - es. 'vuole approfondire le frazioni'"],
    75→  "preferences": ["preferenze di apprendimento espresse - es. 'preferisce esempi visivi'"],
    76→  "learned": ["concetti che lo studente ha capito - es. 'comprende le operazioni base'"]
    77→}
    78→
    79→Se non ci sono informazioni per una categoria, usa un array vuoto.
    80→Max 3 elementi per categoria.`;
    81→
    82→  const userPrompt = messages
    83→    .map((m) => `${m.role === 'user' ? 'STUDENTE' : 'MAESTRO'}: ${m.content}`)
    84→    .join('\n\n');
    85→
    86→  try {
    87→    const result = await chatCompletion(
    88→      [{ role: 'user', content: userPrompt }],
    89→      systemPrompt
    90→    );
    91→
    92→    // Parse JSON from response
    93→    const jsonMatch = result.content.match(/\{[\s\S]*\}/);
    94→    if (jsonMatch) {
    95→      return JSON.parse(jsonMatch[0]);
    96→    }
    97→  } catch (error) {
    98→    logger.error('Failed to extract key facts', { error: String(error) });
    99→  }
   100→
   101→  return { decisions: [], preferences: [], learned: [] };
   102→}
   103→
   104→/**
   105→ * Extract conversation topics
   106→ * Returns list of main subjects discussed
   107→ */
   108→export async function extractTopics(messages: Message[]): Promise<string[]> {
   109→  const provider = getActiveProvider();
   110→  if (!provider) {
   111→    return [];
   112→  }
   113→
   114→  const systemPrompt = `Identifica gli argomenti principali discussi nella conversazione educativa.
   115→
   116→Rispondi SOLO con un array JSON di stringhe, max 5 argomenti.
   117→Esempio: ["Matematica - Frazioni", "Geometria - Perimetro", "Esercizi pratici"]
   118→
   119→Usa termini brevi e chiari.`;
   120→
   121→  const userPrompt = messages
   122→    .map((m) => `${m.role === 'user' ? 'STUDENTE' : 'MAESTRO'}: ${m.content}`)
   123→    .join('\n\n');
   124→
   125→  try {
   126→    const result = await chatCompletion(
   127→      [{ role: 'user', content: userPrompt }],
   128→      systemPrompt
   129→    );
   130→
   131→    // Parse JSON array from response
   132→    const arrayMatch = result.content.match(/\[[\s\S]*\]/);
   133→    if (arrayMatch) {
   134→      return JSON.parse(arrayMatch[0]);
   135→    }
   136→  } catch (error) {
   137→    logger.error('Failed to extract topics', { error: String(error) });
   138→  }
   139→
   140→  return [];
   141→}
   142→
   143→/**
   144→ * Extract learnings about the student
   145→ * These are cross-session insights that help personalize future interactions
   146→ */
   147→export async function extractLearnings(
   148→  messages: Message[],
   149→  _maestroId: string,
   150→  _subject?: string
   151→): Promise<Learning[]> {
   152→  const provider = getActiveProvider();
   153→  if (!provider) {
   154→    return [];
   155→  }
   156→
   157→  const systemPrompt = `Analizza la conversazione e identifica caratteristiche dello studente.
   158→
   159→Categorie disponibili:
   160→- preference: preferenze di apprendimento (es. "Preferisce esempi pratici")
   161→- strength: punti di forza (es. "Buona memoria visiva")
   162→- weakness: difficoltà (es. "Difficoltà con le frazioni")
   163→- interest: interessi espressi (es. "Interessato alla programmazione")
   164→- style: stile di apprendimento (es. "Apprende meglio con esercizi guidati")
   165→
   166→Rispondi SOLO con un array JSON:
   167→[
   168→  {"category": "preference", "insight": "descrizione breve", "confidence": 0.7},
   169→  {"category": "weakness", "insight": "descrizione breve", "confidence": 0.6}
   170→]
   171→
   172→Regole:
   173→- Max 3 insights
   174→- Solo caratteristiche evidenti dalla conversazione
   175→- Confidence da 0.3 (debole) a 0.9 (molto evidente)
   176→- Se non ci sono insights chiari, rispondi con []`;
   177→
   178→  const userPrompt = messages
   179→    .map((m) => `${m.role === 'user' ? 'STUDENTE' : 'MAESTRO'}: ${m.content}`)
   180→    .join('\n\n');
   181→
   182→  try {
   183→    const result = await chatCompletion(
   184→      [{ role: 'user', content: userPrompt }],
   185→      systemPrompt
   186→    );
   187→
   188→    // Parse JSON array from response
   189→    const arrayMatch = result.content.match(/\[[\s\S]*\]/);
   190→    if (arrayMatch) {
   191→      const learnings = JSON.parse(arrayMatch[0]) as Learning[];
   192→      // Validate and filter
   193→      return learnings
   194→        .filter(
   195→          (l) =>
   196→            ['preference', 'strength', 'weakness', 'interest', 'style'].includes(l.category) &&
   197→            l.insight &&
   198→            l.confidence >= 0.3 &&
   199→            l.confidence <= 1
   200→        )
   201→        .slice(0, 3);
   202→    }
   203→  } catch (error) {
   204→    logger.error('Failed to extract learnings', { error: String(error) });
   205→  }
   206→
   207→  return [];
