   416→                : 'systemPrompt' in targetCharacter ? String(targetCharacter.systemPrompt) : '',
   417→            color: targetCharacter.color,
   418→            voice: 'voice' in targetCharacter ? targetCharacter.voice : 'alloy',
   419→            voiceInstructions: 'voiceInstructions' in targetCharacter ? targetCharacter.voiceInstructions : '',
   420→          };
   421→
   422→          // Suggest handoff instead of auto-switching
   423→          suggestHandoff({
   424→            toCharacter: handoffCharacter,
   425→            reason: routingResult.reason,
   426→            confidence: routingResult.intent.confidence,
   427→          });
   428→        }
   429→      }
   430→
   431→      // Send to AI for response (simulated for now - will integrate with chat API)
   432→      const response = await fetch('/api/chat', {
   433→        method: 'POST',
   434→        headers: { 'Content-Type': 'application/json' },
   435→        body: JSON.stringify({
   436→          messages: [
   437→            { role: 'system', content: activeCharacter.systemPrompt },
   438→            ...messages
   439→              .filter((m) => m.role !== 'system')
   440→              .map((m) => ({
   441→                role: m.role,
   442→                content: m.content,
   443→              })),
   444→            { role: 'user', content: userMessage },
   445→          ],
   446→          maestroId: activeCharacter.id,
   447→        }),
   448→      });
   449→
   450→      if (!response.ok) {
   451→        throw new Error('Failed to get response');
   452→      }
   453→
   454→      const data = await response.json();
   455→      const assistantContent = data.content || data.message || '';
   456→      addMessage({ role: 'assistant', content: assistantContent });
   457→
   458→      // Also check AI response for handoff signals (reactive detection)
   459→      if (!pendingHandoff) {
   460→        const handoffAnalysis = analyzeHandoff({
   461→          message: userMessage,
   462→          aiResponse: assistantContent,
   463→          activeCharacter,
   464→          studentProfile: extendedProfile,
   465→          recentMessages: messages.slice(-5).map((m) => ({
   466→            role: m.role === 'system' ? 'assistant' : (m.role as 'user' | 'assistant'),
   467→            content: m.content,
   468→          })),
   469→        });
   470→
   471→        if (handoffAnalysis.shouldHandoff && handoffAnalysis.suggestion && handoffAnalysis.confidence > 0.7) {
   472→          suggestHandoff(handoffAnalysis.suggestion);
   473→        }
   474→      }
   475→    } catch (error) {
   476→      logger.error('Chat error', { error });
   477→      addMessage({
   478→        role: 'assistant',
   479→        content: 'Mi dispiace, ho avuto un problema. Puoi riprovare?',
   480→      });
   481→    } finally {
   482→      setIsLoading(false);
   483→    }
   484→  }, [
   485→    inputValue,
   486→    isLoading,
   487→    activeCharacter,
   488→    addMessage,
   489→    messages,
   490→    extendedProfile,
   491→    routeMessage,
   492→    suggestHandoff,
   493→    pendingHandoff,
   494→  ]);
   495→
   496→  /**
   497→   * Handle key press in input.
   498→   */
   499→  const handleKeyPress = (e: React.KeyboardEvent) => {
   500→    if (e.key === 'Enter' && !e.shiftKey) {
   501→      e.preventDefault();
   502→      handleSend();
   503→    }
   504→  };
   505→
   506→  /**
   507→   * Handle voice mode toggle (for input area).
   508→   */
   509→  const handleVoiceToggle = () => {
   510→    if (mode === 'voice') {
   511→      setMode('text');
   512→    } else {
   513→      setMode('voice');
   514→    }
   515→  };
   516→
   517→  /**
   518→   * Handle voice call (full voice conversation).
   519→   */
   520→  const handleVoiceCall = useCallback(() => {
   521→    if (isVoiceActive) {
   522→      // End voice call
   523→      setIsVoiceActive(false);
   524→      setMode('text');
   525→    } else {
   526→      // Start voice call
   527→      setIsVoiceActive(true);
   528→      setMode('voice');
   529→      // Voice session will be started by VoiceCallOverlay
   530→      // This is a placeholder - Issue #34 tracks voice WebSocket issues
   531→    }
   532→  }, [isVoiceActive, setMode]);
   533→
   534→  /**
   535→   * Handle accepting handoff.
   536→   */
   537→  const handleAcceptHandoff = () => {
   538→    acceptHandoff(extendedProfile);
   539→  };
   540→
   541→  /**
   542→   * Handle manual character switches.
   543→   */
   544→  const handleSwitchToCoach = () => switchToCoach(extendedProfile);
   545→  const handleSwitchToBuddy = () => switchToBuddy(extendedProfile);
   546→  const handleGoBack = () => goBack(extendedProfile);
   547→
   548→  // Render idle state (shouldn't happen with auto-start)
   549→  if (!isActive || !activeCharacter) {
   550→    return (
   551→      <div className="flex items-center justify-center h-full">
   552→        <Button onClick={() => startConversation(extendedProfile)}>
   553→          Inizia una conversazione
   554→        </Button>
   555→      </div>
   556→    );
   557→  }
   558→
   559→  // Video conference layout when tool is active (Issue #36)
   560→  const hasActiveTool = activeTool && activeTool.status !== 'error';
   561→
   562→  return (
   563→    <div className="relative flex flex-col h-[calc(100vh-200px)] max-h-[700px] bg-white dark:bg-slate-900 rounded-2xl shadow-xl overflow-hidden">
   564→      {/* Voice call overlay */}
   565→      <AnimatePresence>
   566→        {isVoiceActive && activeCharacter && (
   567→          <VoiceCallOverlay
   568→            character={activeCharacter}
   569→            onEnd={handleVoiceCall}
   570→            onSessionIdChange={setVoiceSessionId}
   571→          />
   572→        )}
   573→      </AnimatePresence>
   574→
   575→      {/* Header with character info and voice call button - 10% */}
   576→      <ConversationHeader
   577→        currentCharacter={activeCharacter}
   578→        onSwitchToCoach={handleSwitchToCoach}
   579→        onSwitchToBuddy={handleSwitchToBuddy}
   580→        onGoBack={handleGoBack}
   581→        canGoBack={characterHistory.length > 1}
   582→        isVoiceActive={isVoiceActive}
   583→        onVoiceCall={handleVoiceCall}
   584→      />
   585→
   586→      {/* Handoff suggestion */}
   587→      <AnimatePresence>
   588→        {pendingHandoff && (
   589→          <HandoffBanner
   590→            suggestion={pendingHandoff}
   591→            onAccept={handleAcceptHandoff}
   592→            onDismiss={dismissHandoff}
   593→          />
   594→        )}
   595→      </AnimatePresence>
   596→
   597→      {/* Main content area - switches between chat-first and tool-first layouts */}
   598→      {hasActiveTool ? (
   599→        /* VIDEO CONFERENCE LAYOUT: Tool takes center stage (Issue #36) */
   600→        <div className="flex-1 flex flex-col overflow-hidden">
   601→          {/* Tool panel - 70% of remaining space */}
   602→          <div className="flex-[7] overflow-auto border-b border-slate-200 dark:border-slate-700">
   603→            <ToolPanel
   604→              tool={activeTool}
   605→              maestro={activeCharacter ? {
   606→                name: activeCharacter.name,
   607→                avatar: CHARACTER_AVATARS[activeCharacter.id] || '/avatars/default.jpg',
   608→                color: activeCharacter.color,
   609→              } : null}
   610→              onClose={() => setActiveTool(null)}
   611→              isMinimized={isToolMinimized}
   612→              onToggleMinimize={() => setIsToolMinimized(!isToolMinimized)}
   613→              embedded={true}
   614→              sessionId={voiceSessionId}
   615→            />
   616→          </div>
   617→
   618→          {/* Mini chat - 15% of remaining space */}
   619→          <div
   620→            className="flex-[1.5] overflow-y-auto p-2 bg-slate-50 dark:bg-slate-800/50"
   621→            role="log"
   622→            aria-live="polite"
   623→            aria-label="Messaggi recenti"
   624→          >
   625→            {/* Show only last 3 messages in mini view */}
   626→            {messages.slice(-3).map((message) => (
   627→              <div
   628→                key={message.id}
   629→                className={cn(
   630→                  'text-xs py-1 px-2 rounded mb-1',
   631→                  message.role === 'user'
   632→                    ? 'bg-accent-themed/10 text-right'
   633→                    : 'bg-slate-200 dark:bg-slate-700'
   634→                )}
   635→              >
   636→                <span className="font-medium">
   637→                  {message.role === 'user' ? 'Tu' : activeCharacter?.name}:
   638→                </span>{' '}
   639→                {message.content.substring(0, 80)}
   640→                {message.content.length > 80 && '...'}
   641→              </div>
   642→            ))}
   643→            {isLoading && (
   644→              <div className="text-xs py-1 px-2 flex items-center gap-1">
   645→                <Loader2 className="w-3 h-3 animate-spin" />
   646→                <span>{activeCharacter?.name} sta pensando...</span>
   647→              </div>
   648→            )}
   649→          </div>
   650→        </div>
   651→      ) : (
   652→        /* NORMAL LAYOUT: Chat takes full space */
   653→        <div
   654→          className="flex-1 overflow-y-auto p-4"
   655→          role="log"
   656→          aria-live="polite"
   657→          aria-label="Messaggi della conversazione"
   658→        >
   659→          {messages.map((message) => (
   660→            <MessageBubble
   661→              key={message.id}
   662→              message={message}
   663→              activeCharacter={
   664→                message.role === 'assistant' ? activeCharacter : null
   665→              }
   666→            />
   667→          ))}
   668→          {isLoading && (
   669→            <motion.div
   670→              initial={{ opacity: 0 }}
   671→              animate={{ opacity: 1 }}
   672→              className="flex gap-3 mb-4"
   673→            >
   674→              <CharacterAvatar character={activeCharacter} size="sm" />
   675→              <div className="px-4 py-3 bg-slate-100 dark:bg-slate-800 rounded-2xl rounded-bl-md">
   676→                <Loader2 className="w-5 h-5 animate-spin text-slate-500" />
   677→              </div>
   678→            </motion.div>
   679→          )}
   680→          <div ref={messagesEndRef} />
   681→        </div>
   682→      )}
   683→
   684→      {/* Input area - 5% */}
   685→      <div className="p-4 border-t border-slate-200 dark:border-slate-700">
   686→        <div className="flex items-center gap-2">
   687→          {/* Tool buttons - quick access to educational tools */}
   688→          <ToolButtons
   689→            onToolRequest={handleToolRequest}
   690→            disabled={isLoading}
   691→            activeToolId={activeTool?.id}
   692→          />
   693→          <input
   694→            ref={inputRef}
   695→            type="text"
   696→            value={inputValue}
   697→            onChange={(e) => setInputValue(e.target.value)}
   698→            onKeyDown={handleKeyPress}
   699→            placeholder={`Scrivi a ${activeCharacter.name}...`}
   700→            aria-label={`Scrivi un messaggio a ${activeCharacter.name}`}
   701→            className="flex-1 px-4 py-3 bg-slate-100 dark:bg-slate-800 rounded-xl border-0 focus:ring-2 focus:ring-accent-themed outline-none text-slate-900 dark:text-white placeholder:text-slate-500"
   702→            disabled={isLoading}
   703→          />
   704→          <Button
   705→            variant="ghost"
   706→            size="icon"
   707→            onClick={() => setIsMuted(!isMuted)}
   708→            aria-label={isMuted ? 'Attiva audio' : 'Disattiva audio'}
   709→            aria-pressed={isMuted}
   710→          >
   711→            {isMuted ? (
   712→              <VolumeX className="w-5 h-5" />
   713→            ) : (
   714→              <Volume2 className="w-5 h-5" />
   715→            )}
   716→          </Button>
   717→          <Button
   718→            variant="ghost"
   719→            size="icon"
   720→            onClick={handleVoiceToggle}
   721→            aria-label={mode === 'voice' ? 'Passa al testo' : 'Passa alla voce'}
   722→            aria-pressed={mode === 'voice'}
   723→            className={cn(mode === 'voice' && 'bg-red-100 text-red-600')}
   724→          >
   725→            {mode === 'voice' ? (
   726→              <MicOff className="w-5 h-5" />
   727→            ) : (
   728→              <Mic className="w-5 h-5" />
   729→            )}
   730→          </Button>
   731→          <Button
   732→            size="icon"
   733→            onClick={handleSend}
   734→            disabled={!inputValue.trim() || isLoading}
   735→            aria-label="Invia messaggio"
   736→            className="bg-accent-themed hover:bg-accent-themed/90"
   737→          >
   738→            <Send className="w-5 h-5" aria-hidden="true" />
   739→          </Button>
   740→        </div>
   741→      </div>
   742→    </div>
   743→  );
   744→}
