    51→
    52→export type VoiceSessionState =
    53→  | 'idle'
    54→  | 'connecting'
    55→  | 'connected'
    56→  | 'listening'
    57→  | 'processing'
    58→  | 'speaking'
    59→  | 'error';
    60→
    61→export type VoiceConnectionState = 'idle' | 'connecting' | 'connected' | 'error';
    62→
    63→/**
    64→ * Handle returned by useVoiceSession hook.
    65→ * Used to pass voice session state between components without re-creating connections.
    66→ */
    67→export interface VoiceSessionHandle {
    68→  isConnected: boolean;
    69→  isListening: boolean;
    70→  isSpeaking: boolean;
    71→  isMuted: boolean;
    72→  connectionState: VoiceConnectionState;
    73→  connect: (maestro: Maestro, connectionInfo: { provider: 'azure'; proxyPort?: number }) => Promise<void>;
    74→  disconnect: () => void;
    75→  toggleMute: () => void;
    76→}
    77→
    78→export type EmotionType =
    79→  | 'neutral'
    80→  | 'joy'
    81→  | 'excitement'
    82→  | 'curiosity'
    83→  | 'confusion'
    84→  | 'frustration'
    85→  | 'anxiety'
    86→  | 'boredom'
    87→  | 'distraction';
    88→
    89→export interface Emotion {
    90→  type: EmotionType;
    91→  confidence: number;
    92→  color: string;
    93→}
    94→
    95→export interface TranscriptEntry {
    96→  id: string;
