   581→ */
   582→export type ObservationCategory =
   583→  | 'logical_reasoning'       // Archimede
   584→  | 'creativity'              // Leonardo
   585→  | 'verbal_expression'       // Dante
   586→  | 'study_method'            // Montessori
   587→  | 'critical_thinking'       // Socrate
   588→  | 'artistic_sensitivity'    // Mozart
   589→  | 'scientific_curiosity'    // Darwin
   590→  | 'spatial_memory'          // Marco Polo
   591→  | 'historical_understanding' // Giulio Cesare
   592→  | 'mathematical_intuition'  // Pitagora
   593→  | 'linguistic_ability'      // Cicerone
   594→  | 'philosophical_depth'     // Aristotele
   595→  | 'physical_awareness'      // Ippocrate
   596→  | 'experimental_approach'   // Galileo
