   709→  masterVolume: number;        // 0-1
   710→  currentPreset: AudioPreset | null;
   711→  layers: AudioLayer[];
   712→  // Auto-ducking: reduce volume during voice/TTS
   713→  autoDuckEnabled: boolean;
   714→  duckedVolume: number;        // Volume to reduce to when ducking (0-1)
   715→  // Integration with study sessions
   716→  autoStartWithStudy: boolean;
   717→  studySessionAudioMode: AudioMode | null;
   718→  // Error state
   719→  error: string | null;
   720→}
