    94→export async function POST(request: NextRequest) {
    95→  // Rate limiting: 20 requests per minute per IP
    96→  const clientId = getClientIdentifier(request);
    97→  const rateLimit = checkRateLimit(`chat:${clientId}`, RATE_LIMITS.CHAT);
    98→
    99→  if (!rateLimit.success) {
   100→    logger.warn('Rate limit exceeded', { clientId, endpoint: '/api/chat' });
   101→    return rateLimitResponse(rateLimit);
   102→  }
   103→
   104→  try {
   105→    const body: ChatRequest = await request.json();
   106→    const { messages, systemPrompt, maestroId, enableTools = true, requestedTool } = body;
   107→
   108→    if (!messages || !Array.isArray(messages)) {
   109→      return NextResponse.json(
   110→        { error: 'Messages array is required' },
   111→        { status: 400 }
   112→      );
   113→    }
   114→
   115→    // Inject tool context into system prompt if tool is requested (Phase 5)
   116→    let enhancedSystemPrompt = systemPrompt;
   117→    if (requestedTool && TOOL_CONTEXT[requestedTool]) {
   118→      enhancedSystemPrompt = `${systemPrompt}\n\n${TOOL_CONTEXT[requestedTool]}`;
   119→      logger.debug('Tool context injected', { requestedTool, maestroId });
   120→    }
   121→
   122→    // SECURITY: Filter the last user message for safety (Issue #30)
   123→    const lastUserMessage = messages.filter(m => m.role === 'user').pop();
   124→    if (lastUserMessage) {
   125→      const filterResult = filterInput(lastUserMessage.content);
   126→      if (!filterResult.safe && filterResult.action === 'block') {
   127→        logger.warn('Content blocked by safety filter', {
   128→          clientId,
   129→          category: filterResult.category,
   130→          severity: filterResult.severity,
   131→        });
   132→        return NextResponse.json({
   133→          content: filterResult.suggestedResponse,
   134→          provider: 'safety_filter',
   135→          model: 'content-filter',
   136→          blocked: true,
   137→          category: filterResult.category,
   138→        });
   139→      }
   140→    }
   141→
   142→    // Get active provider info for response
   143→    const providerConfig = getActiveProvider();
   144→
   145→    try {
   146→      // Call AI with optional tool definitions
   147→      // Cast to mutable array since chatCompletion expects ToolDefinition[]
   148→      const result = await chatCompletion(messages, enhancedSystemPrompt, {
   149→        tools: enableTools ? ([...CHAT_TOOL_DEFINITIONS] as typeof CHAT_TOOL_DEFINITIONS[number][]) : undefined,
   150→        tool_choice: enableTools ? 'auto' : 'none',
   151→      });
   152→
   153→      // Handle tool calls if present
   154→      if (result.tool_calls && result.tool_calls.length > 0) {
   155→        const toolResults = [];
   156→
   157→        for (const toolCall of result.tool_calls) {
   158→          try {
   159→            const args = JSON.parse(toolCall.function.arguments);
   160→            const toolResult = await executeToolCall(
   161→              toolCall.function.name,
   162→              args,
   163→              { maestroId, conversationId: undefined }
   164→            );
   165→            // Transform to ToolCall interface format expected by ToolResultDisplay
   166→            // Note: type uses function name (e.g., 'create_mindmap') to match ToolType in types/index.ts
   167→            toolResults.push({
   168→              id: toolResult.toolId || toolCall.id,
   169→              type: toolCall.function.name,
   170→              name: toolCall.function.name,
   171→              arguments: args,
   172→              status: toolResult.success ? 'completed' : 'error',
   173→              result: {
   174→                success: toolResult.success,
   175→                data: toolResult.data,
   176→                error: toolResult.error,
   177→              },
   178→            });
   179→          } catch (toolError) {
   180→            logger.error('Tool execution failed', {
   181→              toolCall: toolCall.function.name,
   182→              error: String(toolError),
   183→            });
   184→            const args = JSON.parse(toolCall.function.arguments || '{}');
   185→            toolResults.push({
   186→              id: toolCall.id,
   187→              type: toolCall.function.name,
   188→              name: toolCall.function.name,
   189→              arguments: args,
   190→              status: 'error',
   191→              result: {
   192→                success: false,
   193→                error: toolError instanceof Error ? toolError.message : 'Tool execution failed',
   194→              },
   195→            });
   196→          }
   197→        }
   198→
   199→        // Return response with tool results
   200→        return NextResponse.json({
   201→          content: result.content || '',
   202→          provider: result.provider,
   203→          model: result.model,
   204→          usage: result.usage,
   205→          maestroId,
   206→          toolCalls: toolResults,
   207→          hasTools: true,
   208→        });
   209→      }
   210→
