    if (contextualGreeting) {
      messages = [{
        id: crypto.randomUUID(),
        role: 'assistant',
        content: contextualGreeting,
        timestamp: new Date(),
        characterId: character.id,
        characterType: type,
      }];
    }
  }

  // ... rest of function ...
}
```

---

## Phase 5: Session Rating System

### 5.1 Student Self-Evaluation Component

Create `/src/components/session/session-rating-modal.tsx`:

